SELECT [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Transfer Line].[Document No_], Sum(Val([quantity])) AS qty, Item.[Description 2], [Variable Code].Description AS ColorDescription
FROM ((([Transfer Line] LEFT JOIN (Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) ON [Transfer Line].[Item No_] = Item.No_) LEFT JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]
GROUP BY [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Transfer Line].[Document No_], Item.[Description 2], [Variable Code].Description, [Transfer Header].No_
HAVING (((Item.[Configurator Relation])=3) AND (([Transfer Header].No_)=[forms]![principale]![filtroodtean]));

